// Validate API response — bail out cleanly if sbmercedes.com is down
const resp = $input.item.json;

if (!resp || resp.error || !resp.pageInfo) {
  throw new Error(
    'sbmercedes.com API returned an unexpected response: ' +
    JSON.stringify(resp).substring(0, 200)
  );
}

const totalCount = resp.pageInfo.totalCount;
if (!totalCount || totalCount < 1) {
  throw new Error('pageInfo.totalCount missing or zero — aborting sync');
}

// Pass total count + sync start timestamp forward
return [{
  json: {
    totalCount: totalCount,
    sync_started_at: $('Capture Sync Start').item.json.sync_started_at
  }
}];

// Build array of page offsets based on totalCount
const totalCount = $input.item.json.totalCount;
const syncStart = $input.item.json.sync_started_at;
const pageSize = 100;
const totalPages = Math.ceil(totalCount / pageSize);

const pages = [];
for (let i = 0; i < totalPages; i++) {
  pages.push({
    json: {
      pageStart: i * pageSize,
      pageSize: pageSize,
      totalCount: totalCount,
      totalPages: totalPages,
      pageNumber: i + 1,
      sync_started_at: syncStart
    }
  });
}

return pages;

// Skip pages where the API returned an error
const resp = $input.item.json;
if (!resp || resp.error || !Array.isArray(resp.inventory)) {
  // Log and skip — do not crash the whole sync
  return [{ json: { _skipped: true, reason: 'bad_api_response' } }];
}

const vehicles = resp.inventory;

return vehicles.map(v => {
  // Flatten attribute array into key-value map
  const attrs = {};
  (v.attributes || []).forEach(a => {
    if (a.name) attrs[a.name] = a.value || '';
  });

  // Pricing
  const pricingObj = v.pricing || {};
  const msrpStr = pricingObj.retailPrice || 'N/A';
  const msrpNumeric = parseFloat(msrpStr.replace(/[^0-9.]/g, '')) || null;

  // Year — from title array
  const titleArr = v.title || [];
  const yearMake = titleArr[0] || '';
  const yearMatch = yearMake.match(/(\d{4})/);
  const year = yearMatch ? yearMatch[1] : (attrs.year || '');

  // Mileage — critical for used-car queries
  const rawMileage =
    v.mileage ||
    attrs.mileage ||
    attrs.Mileage ||
    attrs.odometer ||
    attrs.Odometer ||
    (v.certifiedDetails && v.certifiedDetails.odometerReading) ||
    null;
  const mileage = rawMileage ? parseFloat(String(rawMileage).replace(/[^0-9.]/g, '')) || null : null;

  // Detail URL
  const detailPath = v.link || '';
  const detailUrl = detailPath ? 'https://www.sbmercedes.com' + detailPath : '';

  return {
    json: {
      vin:            v.vin || '',
      stock_number:   v.stockNumber || attrs.stockNumber || '',
      year:           year,
      make:           v.make || 'Mercedes-Benz',
      model:          v.model || '',
      trim:           v.trim || attrs.trim || '',
      body_style:     attrs.bodyStyle || attrs.body_style || '',
      exterior_color: attrs.exteriorColor || attrs.exterior_color || '',
      interior_color: attrs.interiorColor || attrs.interior_color || '',
      fuel_type:      v.fuelType || attrs.fuelType || '',
      mileage:        mileage,
      msrp:           msrpStr,
      msrp_numeric:   msrpNumeric,
      condition:      v.condition || '',
      classification: v.classification || '',
      detail_url:     detailUrl,
      scraped_at:     new Date().toISOString(),
      updated_at:     new Date().toISOString()
    }
  };
}).filter(v => v.json.vin !== '' && !v.json._skipped);

// Skip upsert for rows that were skipped upstream (bad API page)
const item = $input.item.json;
if (item._skipped) {
  return [{ json: item }];
}
return [{ json: item }];

// Sync complete — report results
const now = new Date().toISOString();
const syncStart = $('Capture Sync Start').item.json.sync_started_at || 'unknown';

return [{
  json: {
    status:       'sync_complete',
    message:      'Mercedes SB inventory sync finished successfully',
    sync_started: syncStart,
    sync_ended:   now,
    duration_ms:  new Date(now) - new Date(syncStart)
  }
}];
